var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"야단났군…….","JPN":"まいったな……","ENG":"This is troublesome...","TWN":"真是一團糟……"},"stage":{"bg":"SS_ESPR_06","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"눈으로 보고도 믿을 수가 없을 정도야.","JPN":"この目で見ても信じられない。","ENG":"I can't believe what I'm seeing in front of my eyes.","TWN":"就算親眼見到了都覺得難以置信。"},"stage":{"bg":"SS_ESPR_06","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"이곳의 숲, 아니…… 이 세계 자체가 저 파편에게 탐식당하고 있는 건가?","JPN":"この森、いや……この世界自体があの破片に侵食されているのか？","ENG":"Is this forest... No, is the world itself being devoured by that Fragment?","TWN":"這裡的樹林，不……整個世界都在被那個碎片所吞噬嗎？"},"stage":{"bg":"SS_ESPR_06","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"LAKE-4에 격리되어있던 파편과는 비교조차 할 수 없어.","JPN":"LAKE-4に隔離されていた破片とは比べ物にならない。","ENG":"It's incomparable to the Fragment that was quarantined at LAKE-4.","TWN":"根本無法與隔離在LAKE-4上的碎片比較。"},"stage":{"bg":"SS_ESPR_04","bgm":"THEMA_ESPR","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"그나마 다행인 건 봉인 사슬이 없는데도 공격성을 보이지 않는 점이라고 해야겠지.","JPN":"封印の鎖がなくても攻撃してこないのが幸いだな。","ENG":"The only good news is that even without the Sealing Chains, it seems to show no signs of aggressiveness.","TWN":"值得慶倖的是，即使沒有封印鎖鏈，也沒有表現出攻擊性。"},"stage":{"bg":"SS_ESPR_04","bgm":"THEMA_ESPR","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"그렇다면 아직 자의식을 가지지 않았을 때가 기회일지도 모르겠군.","JPN":"それなら、まだ自我をもっていない今がチャンスかもしれない。","ENG":"Then, perhaps there might be an opportunity to kill it before it gains self-consciousness.","TWN":"若是如此，在還沒有自我意識的時候，也許就是機會。"},"stage":{"bg":"SS_ESPR_04","bgm":"THEMA_ESPR","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"오, 오오…….","JPN":"お、おお……","ENG":"Oh... Ooh...!","TWN":"喔，喔喔……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"살아서 내 눈으로 저런 광경을 목격하게 될 줄이야.","JPN":"生きているうちにこんな景色を目にすることができるとは。","ENG":"I never thought I'd see such a sight like this during my lifetime.","TWN":"沒想到我還活著的時候就能親眼目睹此等情景。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"저것이야 말로…… 신의 피를 담은 그릇. 성배의 진정한 모습이네.","JPN":"あれこそ……神の血を宿した器、聖杯の真の姿だ。","ENG":"That is... the vessel for god's blood. The true form of the Holy Grail.","TWN":"那個才是……盛裝著神血的器皿，聖杯的真實面貌。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"누가 입을 열라고 했지? 네놈 생각 따위는 관심 없어.","JPN":"誰が口を開いていいと言った？　貴様の感想など求めてない。","ENG":"Who said you could open your mouth? Nobody cares what you think.","TWN":"誰讓你說話的？我對你這傢伙的想法並不感興趣。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"하지만 저걸 현실에 부상시켰다간, 대환류 이상의 재난이 벌어질 건 불 보듯 뻔하군.","JPN":"だが、あれを現実に浮上させてしまったら、大還流以上の災厄になるのは確かだ。","ENG":"But if that thing emerges in the Normalside, it'll be an even bigger disaster than the Great Gyre.","TWN":"如果讓它出現在現世中，肯定會發生比大環流更糟糕的災難。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"역시 형님은…….","JPN":"やはり兄貴は……","ENG":"Just as I thought...","TWN":"大哥果然……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"형님께서는 저것의 싹을 제거하기 위해, 그렇게 오랜 시간을…….","JPN":"兄貴はあれの芽を摘み取るために、あんなに長い時間を……","ENG":"Sir Burnett spent all that time to remove that thing for good...","TWN":"是為了斬草除根，才花了那麼長時間……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"자네…… 지금 뭘 하려는 거지?","JPN":"君……今何を考えている？","ENG":"Hey... What do you think you're doing?","TWN":"你……這是要做什麼？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"보면 모르겠나? 성배를 말살할 걸세.","JPN":"見てわからないか？　聖杯を末梢する。","ENG":"Can't you tell? I'm going to destroy the Holy Grail.","TWN":"看不出來嗎？我要銷毀聖杯。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"한심하군. 제정신인가?","JPN":"嘆かわしい、正気か？","ENG":"How pathetic. Are you insane?","TWN":"荒謬，你瘋了嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"제정신이냐고? 물론이야.","JPN":"正気だと？　もちろんだ。","ENG":"Am I insane? No, I'm not.","TWN":"瘋了嗎？當然。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"원래 숙주를 죽이는 건, 파편이 폭주할 가능성이 있어서 위험하지만.","JPN":"破片が暴走する可能性があるから本来は宿主を殺すことは危険とされるが……","ENG":"Normally, eliminating the host would be dangerous as it increases the likelihood of the Fragment causing an outburst, but...","TWN":"殺死宿主有可能讓碎片暴走，會很危險。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"지금은 수단과 방법을 가릴 때가 아니야.","JPN":"今は手段を選んでいる場合ではない。","ENG":"now's not the time to be picky about what strategy I take.","TWN":"但現在不是瞻前顧後的時候。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"설령 파편이 폭주하여 내가 죽게 되더라도…….","JPN":"たとえ破片が暴走して俺が死ぬことになっても……","ENG":"Even if the Fragment goes berserk and I die...","TWN":"縱使碎片暴走，會置我於死地……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"지금, 여기서 마무리 지어야만 해. 저걸 현실에 끌고 갈 수는 없어.","JPN":"ここでけじめをつけなければならない。あれを現実に連れて行くわけにはいかない。","ENG":"I must end it here, so it doesn't find its way to the Normalside.","TWN":"現在也必須要在這裡了結。我不允許把它拖到現世中去。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"유감이군.","JPN":"それは残念だ。","ENG":"That's a shame.","TWN":"真是可惜。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"자네는 저걸 보고도…… 그런 시시한 발상 밖에 떠올리지 못하나?","JPN":"君はあれを目にしてもなお……そんなくだらないことしか考えられないのかい？","ENG":"After seeing that... All you can come up with is something so mediocre.","TWN":"你都親眼看到了此等神蹟……卻還只想著那些無聊的想法嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"신적 존재를 이 두 눈으로 직접 목격할 수 있는 절호의 기회야.","JPN":"神なる存在を目撃する絶好のチャンスだ。","ENG":"This is our chance to witness a godlike being with our own two eyes.","TWN":"這是可以親眼目睹神之存在的絕佳機會。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"평범한 인간이 그런 소중한 기회를……!","JPN":"普通の人間がそんな貴重なチャンスを……！","ENG":"How can someone waste such a precious–","TWN":"平凡之人若是有如此寶貴的機會……！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"크헉!","JPN":"がはっ！","ENG":"Kgh!","TWN":"咳呃！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_METAMOR_01"},{"id":"L41_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"말했을 텐데? 자네 생각 따위는 관심 없다고.","JPN":"言ったはずだろ？　貴様の感想は要らない。","ENG":"Have I not made myself clear? I don't care what you think.","TWN":"我說過，我對你的想法不感興趣。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"여기에 주저앉아 네놈 계획이 무력하게 박살나는 걸 보라고, 제임스.","JPN":"貴様はここで貴様の計画が無残に壊れるところを指をくわえて見ているといい。","ENG":"Just stay put and watch your plans crumble right before your eyes, James.","TWN":"你這傢伙就癱坐在這裡，無能為力地看著你的計畫被粉碎吧，詹姆斯。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"이 아이가 파편의 숙주, 성배실험의 피험체인가.","JPN":"この子が破片の宿主、聖杯実験の被検体か。","ENG":"Is that child the host of the Fragment? The victim of the Holy Grail experiment?","TWN":"這個孩子就是碎片的宿主，聖杯實驗的受試者嗎？"},"stage":{"bg":"SS_ESPR_06","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L50_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"마치 꿈이라도 꾸고 있는 듯한 표정이군, 의식은 없는 건가?","JPN":"まるで夢を見ているような顔だな……意識はないのか？","ENG":"It's as if she's dreaming. Is she unconscious?","TWN":"好像一副做夢的表情，沒有什麼意識嗎？"},"stage":{"bg":"SS_ESPR_06","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"하긴…… 차라리 의식이 없는 편이 이 아이에게 더 나을지도 모르겠군.","JPN":"まあ……意識がないほうが、この子にとってはマシなのかもしれないな。","ENG":"Then again... perhaps it is better for her to not be conscious.","TWN":"也是……還不如昏迷不醒，說不定對這孩子更好。"},"stage":{"bg":"SS_ESPR_06","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"잘 가게. 가여운 인생이여.","JPN":"さらばだ、哀れな人生よ。","ENG":"Goodbye, you poor child.","TWN":"好走，可憐的人生啊。"},"stage":{"bg":"SS_ESPR_06","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"부디 다음 생이 있다면…….","JPN":"来世があるなら……","ENG":"May you find peace in the next life–","TWN":"如果有來生的話……"},"stage":{"bg":"SS_ESPR_06","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"커헉……!!","JPN":"くはっ……！！","ENG":"Kuh...!!","TWN":"咳呃……！！"},"stage":{"bg":"SS_ESPR_06","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L10_1","type":"dialog","speaker":"ANNA_PRYDWEN_NPC_NULL","text":{"KOREA":"이야~ 하마터면 방심할 뻔했다고?","JPN":"ああ～油断するところだったわ。","ENG":"Phew! You almost got me right there!","TWN":"哎呀～差點掉以輕心了呢？"},"stage":{"bg":"SS_ESPR_06","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANNA_PRYDWEN_NPC_NULL","face":"UNIT_PRIDE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L11_1","type":"dialog","speaker":"ANNA_PRYDWEN_NPC_NULL","text":{"KOREA":"놀랐어. 이곳에 가장 먼저 도착한 사람이 고고학부장도, 그 역겨운 버넷도 아닌…….","JPN":"驚いたわ、ここに一番早く辿り着けたのが考古学部長でも、あのうっとうしいバーネットでもない……","ENG":"What a surprise to see that the first person to reach here is not the Dean of Archeology nor that disgusting Burnett, but...","TWN":"真是令人驚訝，沒想到最先到達這裡的人既不是考古學教授，也不是那個噁心的伯內特……"},"stage":{"bg":"SS_ESPR_06","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANNA_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"ANNA_PRYDWEN_NPC_NULL","text":{"KOREA":"그저 늙고 병든 사냥개일 줄이야.","JPN":"老いぼれた猟犬だったとはね。","ENG":"a weak, old hound.","TWN":"而是你這條又老又病的獵犬。"},"stage":{"bg":"SS_ESPR_06","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNA_PRYDWEN_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"끄으윽……!!","JPN":"くううっ……！！","ENG":"Argh...!!","TWN":"咳呃……！！"},"stage":{"bg":"SS_ESPR_06","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_PAWN_DAMAGE_DOWN"},{"id":"L15_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"나한테…… 나한테 무슨 짓을 한 거냐!?","JPN":"俺に……何をした！？","ENG":"What... What did you do to me?!","TWN":"你對我……對我做了什麼？！"},"stage":{"bg":"SS_ESPR_06","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ANNA_PRYDWEN_NPC_NULL","text":{"KOREA":"이런 꼬맹이 같은 몸으로 기관의 베테랑이랑 어떻게 싸우겠어?","JPN":"こんなガキの体で機関のベテランとやりあえるわけないでしょう？","ENG":"How can a child like me ever fight against a veteran agent of the Institution, hmm?","TWN":"憑這種小鬼的身體，又怎麼能打得過機關的老手。"},"stage":{"bg":"SS_ESPR_06","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNA_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ANNA_PRYDWEN_NPC_NULL","text":{"KOREA":"그래서 파편을 좀 썼지. 너한테 말이야.","JPN":"破片を使ったの。あなたの体にね。","ENG":"So, I used a bit of the Fragment on you.","TWN":"所以我用了碎片，當然，是在你的身上。"},"stage":{"bg":"SS_ESPR_06","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNA_PRYDWEN_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"뭐라고!?","JPN":"何だと！？","ENG":"What?!","TWN":"什麼？！"},"stage":{"bg":"SS_ESPR_06","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L22_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"끄아아, 아아아악……!","JPN":"くああ、ああああ……っ！！","ENG":"Aaagh...! AAARGH...!!","TWN":"呃啊啊，啊啊啊啊……！"},"stage":{"bg":"SS_ESPR_06","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANNA_PRYDWEN_NPC_NULL","face":"UNIT_PRIDE"}}}},{"id":"L23_1","type":"dialog","speaker":"ANNA_PRYDWEN_NPC_NULL","text":{"KOREA":"하하, 몸이 풍선처럼 부풀어 오르는 꼴이 볼만한데?","JPN":"あはは、体が風船みたいに腫れあがってる！　見ものだね～！","ENG":"Hah hah. It's pretty fun to watch you blow up like a balloon.","TWN":"哈哈，身體像氣球一樣鼓起來的樣子真是值得一看啊？"},"stage":{"bg":"SS_ESPR_06","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANNA_PRYDWEN_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L24_1","type":"dialog","speaker":"ANNA_PRYDWEN_NPC_NULL","text":{"KOREA":"아깝게 됐어~ 버넷이 이꼴을 직접 봤어야 했는데!","JPN":"バーネットがこのざまを見れたらよかったのに、残念だわ。","ENG":"What a pity! Burnett should've been here to see you like this!","TWN":"好可惜~如果伯內特能親眼看到你這個樣子就好了！"},"stage":{"bg":"SS_ESPR_06","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANNA_PRYDWEN_NPC_NULL","face":"UNIT_PRIDE"}}}},{"id":"L29_1","type":"dialog","speaker":"ANNA_PRYDWEN_NPC_NULL","text":{"KOREA":"핫하! 그걸 지금 총질이라고 한 거야?","JPN":"あはは！　今のは何？","ENG":"Hah hah! You call that shooting?","TWN":"哈哈！你管那叫射擊嗎？"},"stage":{"bg":"SS_ESPR_06","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ANNA_PRYDWEN_NPC_NULL","face":"UNIT_LAUGH"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L30_1","type":"dialog","speaker":"ANNA_PRYDWEN_NPC_NULL","text":{"KOREA":"역시 너흰 버넷이 없으면, 정장입고 총싸움하는 애송이들뿐이구나?","JPN":"やっぱりお前たちはバーネットがいないと、スーツを着て射撃ごっこしてるガキどもに過ぎないわね！","ENG":"I see. So without Burnett, you're just a bunch of kids who shoot guns while wearing suits, huh?","TWN":"果然沒有伯內特，你們就只是些學大人穿西裝，乳臭未乾的小鬼！"},"stage":{"bg":"SS_ESPR_06","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ANNA_PRYDWEN_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L32_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"크아아악……!! 으아아악……!!","JPN":"くわああっ……！！　ああああっ……！！","ENG":"Aaah...!! Aaargh...!!","TWN":"呃啊啊啊……！！呃啊啊啊……！！"},"stage":{"bg":"SS_ESPR_06","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ANNA_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_MONSTER_PAWN_DAMAGE_DOWN"},{"id":"L33_1","type":"dialog","speaker":"ANNA_PRYDWEN_NPC_NULL","text":{"KOREA":"저항해도 소용없어.","JPN":"抵抗しても無駄よ。","ENG":"It's no use resisting.","TWN":"就算反抗也沒有用。"},"stage":{"bg":"SS_ESPR_06","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ANNA_PRYDWEN_NPC_NULL","face":"UNIT_PRIDE"}}}},{"id":"L34_1","type":"dialog","speaker":"ANNA_PRYDWEN_NPC_NULL","text":{"KOREA":"그릇으로서의 자질이 없는 인간은, 극미량의 파편만으로도 넘쳐버려 잔해가 되거든.","JPN":"器として素質のない人間は、微量の破片だけでも形を保てず残骸になるの。","ENG":"Any human who is not qualified to become a vessel will become a Remains by even the smallest quantity of the Fragment.","TWN":"沒有資質成為器皿的人，哪怕是極微量的碎片也會溢出，最後變成殘骸。"},"stage":{"bg":"SS_ESPR_06","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ANNA_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"아아, 아아악……!","JPN":"ああ、ああああっ……！","ENG":"Ahh... Aaagh...!","TWN":"啊啊，啊啊啊……！"},"stage":{"bg":"SS_ESPR_06","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNA_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L41_1","type":"dialog","speaker":"ANNA_PRYDWEN_NPC_NULL","text":{"KOREA":"그럼, 너는 얼마나 버틸 수 있을까, 늙은 사냥개?","JPN":"お前はどれぐらい持つかしらね？　老いた猟犬さん。","ENG":"Then, let's see how long you can last, you old hound.","TWN":"那麼，你又能堅持多久呢，老獵犬？"},"stage":{"bg":"SS_ESPR_06","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNA_PRYDWEN_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"ANNA_PRYDWEN_NPC_NULL","text":{"KOREA":"뭐야……?","JPN":"なに……？","ENG":"Huh…?","TWN":"怎麼回事……？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNA_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"ANNA_PRYDWEN_NPC_NULL","text":{"KOREA":"다 와 놓고, 이런 곳에서 뻗어 있던 거야?","JPN":"ここまで来ておいてバテちゃってたの？","ENG":"You made it all the way here, but you chose to just lie there?","TWN":"你怎麼還在這裡躺著？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNA_PRYDWEN_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"설마, 당신은……?","JPN":"まさかあなたは……？","ENG":"Wait, you're...?","TWN":"難道，你是……？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L1_1","type":"dialog","speaker":"ANNA_PRYDWEN_NPC_NULL","text":{"KOREA":"일일이 설명하기도 귀찮네~","JPN":"いちいち説明するのも面倒くさいわね。","ENG":"It's such a hassle to explain every time.","TWN":"說明起來有點麻煩……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNA_PRYDWEN_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"ANNA_PRYDWEN_NPC_NULL","text":{"KOREA":"자세히 말하자면 복잡해지니까…… 네가 아는 맥크레디가 맞다고 치자.","JPN":"詳しくいうとややこしくなるから……お前の知っているマクレディーということにしておきましょう。","ENG":"I won't go into any detail... so let's just say I'm the MacCready you know of.","TWN":"不，或許會變得更複雜……就當是你認識的那個麥克蕾蒂吧。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNA_PRYDWEN_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ANNA_PRYDWEN_NPC_NULL","text":{"KOREA":"파편을 소모해서, 대충 응급조치는 해놨어.","JPN":"破片で応急手当はしておいたわ。","ENG":"I used some of my Fragment to give you first aid.","TWN":"我消耗了碎片，為你緊急處理了一下。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANNA_PRYDWEN_NPC_NULL","face":"UNIT_PRIDE"}}}},{"id":"L6_1","type":"dialog","speaker":"ANNA_PRYDWEN_NPC_NULL","text":{"KOREA":"없어진 팔이 잔해처럼 촉수가 되어버렸지만, 움직일 수만 있으면 딱히 상관없지?","JPN":"なくなった腕が残骸みたいな触手になってしまったけど、動かせるなら別にいいわよね？","ENG":"Although your lost arm will now become a tentacle like a Remains, it's still better to be able to move around, right?","TWN":"雖說失去的手臂像殘骸一樣變成了觸手，但只要能動就沒什麼關係吧？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANNA_PRYDWEN_NPC_NULL","face":"UNIT_LAUGH"}}}},{"id":"L8_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"역시 신탁은 틀리지 않았군.","JPN":"やはり神託は間違ってなかった。","ENG":"The prophecy was true.","TWN":"果然神喻沒有錯。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"마지막에 성배에 다다르는 건 바로 나인가……?","JPN":"最後に聖杯に辿り着くのはこの私なのか……？","ENG":"Will I be the one to reach the Holy Grail in the end...?","TWN":"最後到達聖杯的人就是我嗎……？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ANNA_PRYDWEN_NPC_NULL","text":{"KOREA":"신탁? 무슨 헛소리야? 노망났어?","JPN":"神託？　何とぼけたこと言ってるの？　ボケたの？","ENG":"Prophecy? What are you talking about? Have you gone insane?","TWN":"神喻？你在胡說八道什麼？老糊塗了嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNA_PRYDWEN_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ANNA_PRYDWEN_NPC_NULL","text":{"KOREA":"그보다, 네 휘하에 있는 학회원들을 전부 이곳에 불러 모아줄래?","JPN":"それより、お前の旗下にある学会員を全員ここに集めてくれない？","ENG":"Anyway, could you gather all the Society Members under your command?","TWN":"好了，把你麾下的學會成員都叫到這裡來吧。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANNA_PRYDWEN_NPC_NULL","face":"UNIT_PRIDE"}}}},{"id":"L15_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"그 말씀은……?","JPN":"それはどういう……？","ENG":"That means...?","TWN":"你的意思是……？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANNA_PRYDWEN_NPC_NULL","face":"UNIT_PRIDE"}}}},{"id":"L16_1","type":"dialog","speaker":"ANNA_PRYDWEN_NPC_NULL","text":{"KOREA":"내가 얼마나 오랜 세월 이 때를 기다려 왔는 줄 알아?","JPN":"私がどれほどこの時を待っていたか、わからないでしょう？","ENG":"Do you know how long I've waited for this moment?","TWN":"你知道我等這一刻等了多久嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANNA_PRYDWEN_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L17_1","type":"dialog","speaker":"ANNA_PRYDWEN_NPC_NULL","text":{"KOREA":"곧 기관 녀석들이 들이 닥칠 거야. 이 순간을 방해받을 수는 없지.","JPN":"もうすぐ機関の奴らが押しかけてくるわ。この瞬間をみすみす逃すつもりはないの。","ENG":"The Institution bastards are going to come any second now, and I can't have them disturb this moment.","TWN":"機關的傢伙很快就會闖進來了，可不能再讓他們打擾……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANNA_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"ANNA_PRYDWEN_NPC_NULL","text":{"KOREA":"겁도 없이 발을 들인 사냥개들을 제거하고, 성배와 함께 현실로 돌아가 의식을 준비한다.","JPN":"ここに足を踏み入れた猟犬たちを排除して、聖杯と共に現実に戻って儀式を準備するわ。","ENG":"After ending the daring hounds over there, we head back to the Normalside with the Holy Grail to prepare for the ritual.","TWN":"除掉大膽闖進來的獵犬，然後舉行與聖杯一起回到現世的準備儀式。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANNA_PRYDWEN_NPC_NULL","face":"UNIT_PRIDE"}}}},{"id":"L19_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANNA_PRYDWEN_NPC_NULL","face":"UNIT_PRIDE"}}}},{"id":"L21_1","type":"dialog","speaker":"ANNA_PRYDWEN_NPC_NULL","text":{"KOREA":"학회는 늘 이름을 바꿔가면서 존속해 왔지.","JPN":"学会は名前を変えながら今まで存続してきた。","ENG":"The Society has been around for eons. Always changing names and concealing their identity.","TWN":"沒錯，學會不斷更換名稱，一直延續到現在。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNA_PRYDWEN_NPC_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L22_1","type":"dialog","speaker":"ANNA_PRYDWEN_NPC_NULL","text":{"KOREA":"변혁의 계기를 손에 넣었으니, 새로운 학회에 대한 명분도 충분해.","JPN":"変革のチャンスを手に入れたから、新しい学会を立てる大儀としても十分ね。","ENG":"I have obtained the spark of revolution, which provides sufficient justification for a new Society.","TWN":"既然拿到了可以變革的契機，成立新的學會的名分也就夠了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNA_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ANNA_PRYDWEN_NPC_NULL","text":{"KOREA":"뭐, 두고 보자고.","JPN":"まあ、見てなさい。","ENG":"We'll see.","TWN":"走著瞧吧。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNA_PRYDWEN_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ANNA_PRYDWEN_NPC_NULL","text":{"KOREA":"돌아가면, 은혜도 모르는 배은망덕한 것들을 전부 숙청시켜 버릴 테니까.","JPN":"戻ったら、恩知らずどもを全部粛清してやるから。","ENG":"I'll purge every ingrate once I get back.","TWN":"回去後，我就把那些忘恩負義的東西全都給除掉。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNA_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};